fli9puv.css:
--heading-size: var(--h3, to-rem(32px));
  --price-size: to-rem(60px);
  --inline-sidebar-gap: 4ex;
  li:has(> &) {
    display: flex;
  }
  padding: var(--space-m, 1rem);
  border: var(--border, 1px solid black);
  border-radius: var(--radius, 0.5rem);
  position: relative;
  display: flex;
  flex-direction: column;
  gap: var(--content-gap);
  flex: 1;
  isolation: isolate;
  :has(> &) {
    container-type: inline-size;
  }
  @container (inline-size >= to-rem(800px)) {
    --price-size: to-rem(80px);
    display: grid;
    align-items: stretch;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    grid-template-areas:
      'header side'
      'features side';
    grid-template-rows: 1fr;
    &::after {
      content: '';
      background: var(--neutral-ultra-light);
      inline-size: 60%;
      block-size: 100%;
      top: 0;
      right: 0;
      display: flex;
      position: absolute;
      z-index: -1;
      /* Begin Fade Left */
      --fade-amount: 25%;
      -webkit-mask-image: linear-gradient(to right, transparent 0%, black var(--fade-amount));
      mask-image: linear-gradient(to right, transparent 0%, black var(--fade-amount));
      /* End Fade Left */
    }
  }

