awuvulc.css:
/* Feat: Corner Ribbons */
  :has(> &) {
    position: relative;
    overflow: clip;
  }
  position: absolute;
  display: block;
  padding: var(--ribbon-padding, 0.5em 1em);
  background-color: var(--ribbon-background-color, var(--primary));
  box-shadow: var(--ribbon-shadow, 0 5px 10px var(--neutral-trans-10));
  text-align: center;
  font-size: var(--ribbon-text-size, var(--text-xs));
  color: var(--ribbon-text-color, var(--white));
  inline-size: var(--ribbon-width, 300px);
  line-height: 1.2;
  text-transform: uppercase;
  /* Positioning */
  inset-block-start: var(--ribbon-offset, -2em);
    inset-inline-end: var(--ribbon-offset, -2em);
    transform: var(--ribbon-transform, translateY(-100%) rotate(90deg) translateX(70.71067811865476%) rotate(-45deg));
    transform-origin: var(--ribbon-transform-origin, bottom right);

  &[data-ribbon-position='top-left'] {
    --ribbon-transform: translateY(-100%) rotate(90deg) translateX(70.71067811865476%) rotate(-135deg);
    --ribbon-transform-origin: bottom left;
    inset-block-start: var(--ribbon-offset);
    inset-inline-start: var(--ribbon-offset);
    transform: var(--ribbon-transform);
    transform-origin: var(--ribbon-transform-origin);
  }
